-- Mineral spawn probability data extracted from Star Citizen Game2.dcb (4.x)
CREATE TABLE IF NOT EXISTS mineral_spawns (
  id             BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  system         TEXT NOT NULL,
  body           TEXT NOT NULL,
  body_type      TEXT NOT NULL,
  parent_body    TEXT,
  mineral        TEXT NOT NULL,
  mining_type    TEXT NOT NULL,
  spawn_prob_pct NUMERIC(6,2) NOT NULL,
  group_prob     NUMERIC(6,2),
  data_version   TEXT DEFAULT '4.x',
  source_file    TEXT
);

ALTER TABLE mineral_spawns ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public read" ON mineral_spawns FOR SELECT USING (true);

GRANT SELECT ON mineral_spawns TO anon, authenticated;


CREATE INDEX idx_mineral_spawns_body ON mineral_spawns (system, body);
CREATE INDEX idx_mineral_spawns_mineral ON mineral_spawns (mineral);
CREATE INDEX idx_mineral_spawns_mining_type ON mineral_spawns (mining_type);